#include <stdio.h>
void solve() {
    int n, d;
    scanf("%d %d", &d, &n);
    int ans = n;
    for (int i = 1; i <= d; i++) {
        ans = ans * (ans + 1) / 2;
    }
    printf("%d\n", ans);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        solve();
    }
    return 0;
}

